qry:select.qry:xquery:
					for $r in sql('
				SELECT 
					t0.oi_dictado as oi_dictado,
					t0.c_dictado as c_dictado,
					t0.c_estado as c_estado,
					t0.oi_curso as oi_curso,
					t0.f_inicio as f_inicio
					{%? (#SOURCE:@oi_personal_emp!='')	
							{% ,	CYD02_INSCRIPTOS.oi_personal_emp %} 
							{% %} 
					%}		 
				FROM 
					CYD02_DICTADOS as t0
					{%? (#SOURCE:@oi_personal_emp!='')	
							{% ,	CYD02_INSCRIPTOS JOIN t0.oi_dictado INNER CYD02_INSCRIPTOS.oi_dictado %}
							{% %} 
					%}
				WHERE 1=1
					{%? (#SOURCE:@oi_curso!='')	{% AND t0.oi_curso = {#SOURCE:@oi_curso} %} {% %} %}
					{%? (#SOURCE:@c_estado!='')	{% AND t0.c_estado = {#SOURCE:@c_estado} %} {% %} %}
					{%? (#SOURCE:@oi_personal_emp!='')	{% AND CYD02_INSCRIPTOS.oi_personal_emp = {#SOURCE:@oi_personal_emp} %} {% %} %}
	    		{%? (#SOURCE:@f_desde!='') {% AND t0.f_inicio >= {Datetime(#SOURCE:@f_desde)} %} {% %} %}
	    		{%? (#SOURCE:@f_hasta!='') {% AND t0.f_fin <= {Datetime(#SOURCE:@f_hasta)+1} %} {% %} %}       		
	    	  {%? (string(#SOURCE:DICTADOS/DICTADO/@id)!='') {% AND t0.oi_dictado in ({%=string(#SOURCE:DICTADOS/DICTADO/@id) %}) %} {%  %} %}
    	  ORDER BY 
	     	  {%? (#SOURCE:@ATRIB_ORDEN1!='')	{% {%=#SOURCE:@ATRIB_ORDEN1%} {%? (#SOURCE:@ORDEN1!='') {% {%=#SOURCE:@ORDEN1%}, %} {% ASC, %}	%} %} {% %} %}
	     	  {%? (#SOURCE:@ATRIB_ORDEN2!='')	{% {%=#SOURCE:@ATRIB_ORDEN2%} {%? (#SOURCE:@ORDEN2!='') {% {%=#SOURCE:@ORDEN2%}, %} {% ASC, %}	%} %} {% %} %}
	     		{%? (#SOURCE:@ATRIB_ORDEN3!='')	{% {%=#SOURCE:@ATRIB_ORDEN3%} {%? (#SOURCE:@ORDEN3!='') {% {%=#SOURCE:@ORDEN3%}, %} {% ASC, %}	%} %} {% %} %}
	     		{%? (#SOURCE:@ATRIB_ORDEN4!='')	{% {%=#SOURCE:@ATRIB_ORDEN4%} {%? (#SOURCE:@ORDEN4!='') {% {%=#SOURCE:@ORDEN4%}, %} {% ASC, %}	%} %} {% %} %}     		     		
	     		oi_dictado ASC
			')/ROWS/ROW

		for $r in sql('
	SELECT 1 AS sel
	FROM CYD02_ASIST_CLASE
	WHERE CYD02_ASIST_CLASE.oi_inscripto = {#SOURCE:@oi_inscripto} 
	AND CYD02_ASIST_CLASE.oi_clase_dictado = {#SOURCE:@oi_clase}
')/ROWS/ROW
